import{_ as e,o as d,c as o,ai as a}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"Terminal Detection","description":"Terminal environment detection capabilities, supported terminals, and IDE theme adaptation.","frontmatter":{"title":"Terminal Detection","description":"Terminal environment detection capabilities, supported terminals, and IDE theme adaptation.","outline":[2,3]},"headers":[],"relativePath":"cli/terminal-detection.md","filePath":"cli/terminal-detection.md","lastUpdated":0}'),i={name:"cli/terminal-detection.md"};function r(c,t,n,l,s,m){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="terminal-detection" tabindex="-1">Terminal Detection <a class="header-anchor" href="#terminal-detection" aria-label="Permalink to “Terminal Detection”">​</a></h1><p>The terminal detection system (<code>terminal/</code>) automatically identifies the user&#39;s environment and adapts the UI accordingly.</p><h2 id="detection-capabilities" tabindex="-1">Detection Capabilities <a class="header-anchor" href="#detection-capabilities" aria-label="Permalink to “Detection Capabilities”">​</a></h2><table tabindex="0"><thead><tr><th>Detection</th><th>Method</th><th>Fallback</th></tr></thead><tbody><tr><td>Terminal type</td><td>Environment variables (priority-ordered)</td><td><code>&quot;Terminal&quot;</code></td></tr><tr><td>Shell</td><td><code>PSModulePath</code>/<code>COMSPEC</code> (Windows), <code>$SHELL</code> (Unix)</td><td><code>&quot;unknown&quot;</code></td></tr><tr><td>Color profile</td><td><code>COLORTERM</code> env, <code>termenv</code> profile</td><td><code>&quot;TrueColor&quot;</code></td></tr><tr><td>Background color</td><td>OSC 11, settings.json, theme file, lookup table</td><td><code>#0A0910</code></td></tr><tr><td>Nerd Font</td><td>IDE settings.json <code>fontFamily</code> contains &quot;Nerd&quot;</td><td><code>false</code></td></tr><tr><td>Git branch</td><td><code>.git/HEAD</code> parsing</td><td><code>&quot;&quot;</code></td></tr><tr><td>Accent color</td><td>IDE color customizations, theme file, lookup table</td><td><code>#607088</code></td></tr><tr><td>Editor background</td><td>IDE color customizations, theme file, lookup table</td><td><code>#2c2d3a</code></td></tr></tbody></table><h2 id="supported-terminals" tabindex="-1">Supported Terminals <a class="header-anchor" href="#supported-terminals" aria-label="Permalink to “Supported Terminals”">​</a></h2><table tabindex="0"><thead><tr><th>Terminal</th><th>Detection Method</th></tr></thead><tbody><tr><td>Cursor</td><td><code>CURSOR_TRACE_ID</code> / <code>CURSOR_EXTENSION_HOST_ROLE</code></td></tr><tr><td>Windsurf</td><td><code>WINDSURF_PID</code></td></tr><tr><td>VS Code</td><td><code>VSCODE_PID</code> / <code>TERM_PROGRAM=vscode</code></td></tr><tr><td>Windows Terminal</td><td><code>WT_SESSION</code></td></tr><tr><td>WezTerm</td><td><code>WEZTERM_PANE</code></td></tr><tr><td>iTerm2</td><td><code>ITERM_SESSION_ID</code> / <code>TERM_PROGRAM=iTerm.app</code></td></tr><tr><td>Alacritty</td><td><code>ALACRITTY_WINDOW_ID</code></td></tr><tr><td>Kitty</td><td><code>KITTY_WINDOW_ID</code></td></tr><tr><td>Hyper</td><td><code>TERM_PROGRAM=Hyper</code></td></tr><tr><td>Terminal.app</td><td><code>TERM_PROGRAM=Apple_Terminal</code></td></tr><tr><td>ConEmu</td><td><code>ConEmuPID</code></td></tr></tbody></table><h2 id="theme-adaptation" tabindex="-1">Theme Adaptation <a class="header-anchor" href="#theme-adaptation" aria-label="Permalink to “Theme Adaptation”">​</a></h2><p>For IDE terminals (VS Code, Cursor, Windsurf), the system:</p><ol><li>Reads <code>settings.json</code> (platform-specific path, JSONC-comment-stripped)</li><li>Extracts <code>workbench.colorTheme</code> and <code>colorCustomizations</code></li><li>Finds matching theme extension files for accent/background colors</li><li>Falls back to a lookup table of 19 known themes</li><li>Applies <code>styles.ApplyTheme(accentHex)</code> to override Primary color and rebuild cached styles</li><li>Applies <code>styles.ApplySecondary(editorBgHex)</code> to match inactive tab backgrounds</li><li>Computes atmosphere color for splash screen blending</li></ol>',9)])])}const u=e(i,[["render",r]]);export{h as __pageData,u as default};
